        if lhs.payeePubkey != rhs.payeePubkey {
            return false
        }
        if lhs.paymentHash != rhs.paymentHash {
            return false
        }
        if lhs.description != rhs.description {
            return false
        }
        if lhs.amountMsat != rhs.amountMsat {
            return false
