public enum Error: Swift.Error {

    
    
    case DuplicateNode(code: Int32, msg: String, values: [String: String]
    )
    case NoSuchNode(code: Int32, msg: String, values: [String: String]
    )
    case UnparseableCreds(code: Int32, msg: String, values: [String: String]
    )
    case PhraseCorrupted(code: Int32, msg: String, values: [String: String]
    )
    case Rpc(code: Int32, msg: String, values: [String: String]
    )
    case Argument(code: Int32, msg: String, values: [String: String]
    )
    case Other(code: Int32, msg: String, values: [String: String]
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeError: FfiConverterRustBuffer {
    typealias SwiftType = Error

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> Error {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .DuplicateNode(
            code: try FfiConverterInt32.read(from: &buf), 
            msg: try FfiConverterString.read(from: &buf), 
            values: try FfiConverterDictionaryStringString.read(from: &buf)
            )
        case 2: return .NoSuchNode(
            code: try FfiConverterInt32.read(from: &buf), 
            msg: try FfiConverterString.read(from: &buf), 
            values: try FfiConverterDictionaryStringString.read(from: &buf)
            )
        case 3: return .UnparseableCreds(
            code: try FfiConverterInt32.read(from: &buf), 
            msg: try FfiConverterString.read(from: &buf), 
            values: try FfiConverterDictionaryStringString.read(from: &buf)
            )
        case 4: return .PhraseCorrupted(
            code: try FfiConverterInt32.read(from: &buf), 
            msg: try FfiConverterString.read(from: &buf), 
            values: try FfiConverterDictionaryStringString.read(from: &buf)
            )
        case 5: return .Rpc(
            code: try FfiConverterInt32.read(from: &buf), 
            msg: try FfiConverterString.read(from: &buf), 
            values: try FfiConverterDictionaryStringString.read(from: &buf)
            )
        case 6: return .Argument(
            code: try FfiConverterInt32.read(from: &buf), 
            msg: try FfiConverterString.read(from: &buf), 
            values: try FfiConverterDictionaryStringString.read(from: &buf)
            )
        case 7: return .Other(
            code: try FfiConverterInt32.read(from: &buf), 
            msg: try FfiConverterString.read(from: &buf), 
            values: try FfiConverterDictionaryStringString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: Error, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .DuplicateNode(code,msg,values):
            writeInt(&buf, Int32(1))
            FfiConverterInt32.write(code, into: &buf)
            FfiConverterString.write(msg, into: &buf)
            FfiConverterDictionaryStringString.write(values, into: &buf)
            
        
        case let .NoSuchNode(code,msg,values):
            writeInt(&buf, Int32(2))
            FfiConverterInt32.write(code, into: &buf)
            FfiConverterString.write(msg, into: &buf)
            FfiConverterDictionaryStringString.write(values, into: &buf)
            
        
        case let .UnparseableCreds(code,msg,values):
            writeInt(&buf, Int32(3))
            FfiConverterInt32.write(code, into: &buf)
            FfiConverterString.write(msg, into: &buf)
            FfiConverterDictionaryStringString.write(values, into: &buf)
            
        
        case let .PhraseCorrupted(code,msg,values):
            writeInt(&buf, Int32(4))
            FfiConverterInt32.write(code, into: &buf)
            FfiConverterString.write(msg, into: &buf)
            FfiConverterDictionaryStringString.write(values, into: &buf)
            
        
        case let .Rpc(code,msg,values):
            writeInt(&buf, Int32(5))
            FfiConverterInt32.write(code, into: &buf)
            FfiConverterString.write(msg, into: &buf)
            FfiConverterDictionaryStringString.write(values, into: &buf)
            
        
        case let .Argument(code,msg,values):
            writeInt(&buf, Int32(6))
            FfiConverterInt32.write(code, into: &buf)
            FfiConverterString.write(msg, into: &buf)
            FfiConverterDictionaryStringString.write(values, into: &buf)
            
        
        case let .Other(code,msg,values):
            writeInt(&buf, Int32(7))
            FfiConverterInt32.write(code, into: &buf)
            FfiConverterString.write(msg, into: &buf)
            FfiConverterDictionaryStringString.write(values, into: &buf)
            
        }
    }
}


